    def _sb_item(self, parent, label, count_var, dot_color, command=None, nav_key=None):
        row = tk.Frame(parent, bg=C["sidebar"], padx=16, pady=6, cursor="hand2")
        row.pack(fill="x")

        # Thin accent bar on the left — the persistent "you are here" marker
        # for the active view (invisible sidebar-on-sidebar otherwise).
        bar = tk.Frame(row, bg=C["sidebar"], width=3, height=18)
        bar.pack(side="left", padx=(0, 7))
        bar.pack_propagate(False)

        dot = tk.Canvas(row, width=8, height=8, bg=C["sidebar"], highlightthickness=0)
        dot.create_oval(1, 1, 7, 7, fill=dot_color, outline="")
        dot.pack(side="left", padx=(0, 10))

        lbl = tk.Label(row, text=label, font=("Segoe UI", 10),
                       fg=C["text"], bg=C["sidebar"])
        lbl.pack(side="left")
        tk.Label(row, textvariable=count_var, font=("Segoe UI", 9),
                 fg=C["text_dim"], bg=C["sidebar"]).pack(side="right")

        def _is_active():
            return nav_key is not None and getattr(self, "_active_view", None) == nav_key

        def _bg(color):
            row.config(bg=color)
            for w in row.winfo_children():
                try: w.config(bg=color)
                except Exception: pass
            if _is_active():
                bar.config(bg=C["accent_blue"])

        def _restyle():
            if _is_active():
                _bg(C["hover"])
                lbl.config(font=("Segoe UI", 10, "bold"))
            else:
                _bg(C["sidebar"])
                lbl.config(font=("Segoe UI", 10))

        row.bind("<Enter>", lambda e: _bg(C["hover"]))
        row.bind("<Leave>", lambda e: _restyle())
        if command:
            row.bind("<Button-1>", lambda e: command())
            for w in row.winfo_children():
                w.bind("<Button-1>", lambda e: command())
        if nav_key is not None:
            self._nav_restyles[nav_key] = _restyle
            _restyle()

    def _set_active_nav(self):
        for restyle in getattr(self, "_nav_restyles", {}).values():
            restyle()

    def _rebuild_plans_sidebar(self):
        for w in self._plans_frame.winfo_children():
            w.destroy()
        tk.Label(self._plans_frame, text="ACTIVE PLANS", font=("Segoe UI", 8, "bold"),
                 fg=C["text_muted"], bg=C["sidebar"]).pack(anchor="w", pady=(0, 6))

        for plan in self.plans:
            pid      = plan["id"]
            pname    = plan["name"]
            pcolor   = plan.get("color", C["accent_blue"])
            pday     = self._plan_day_for(plan)
            ptotal   = self._total_days_for(plan)
            by_day   = self._tasks_by_day_for(plan)
            today_t  = by_day.get(pday, [])
            done_t   = sum(1 for t in today_t
                           if self.completions.get((pid, pday, t.get("task", "")), False))

            row = tk.Frame(self._plans_frame, bg=C["sidebar"], pady=3)
            row.pack(fill="x")

            dot = tk.Canvas(row, width=8, height=8, bg=C["sidebar"], highlightthickness=0)
            dot.create_oval(1, 1, 7, 7, fill=pcolor, outline="")
            dot.pack(side="left", padx=(0, 6))

            name_lbl = tk.Label(row, text=_ellipsize(pname, 22), font=("Segoe UI", 9, "bold"),
                                fg=C["text"], bg=C["sidebar"], anchor="w")
            name_lbl.pack(side="left", fill="x", expand=True)
            if len(pname) > 22:
                Hovertip(name_lbl, pname)

            day_lbl = tk.Label(row, text=f"d{pday}", font=("Segoe UI", 8),
                               fg=C["text_muted"], bg=C["sidebar"])
            day_lbl.pack(side="right")

            sub = tk.Frame(self._plans_frame, bg=C["sidebar"])
            sub.pack(fill="x", padx=(14, 0), pady=(0, 4))
            tk.Label(sub, text=f"{done_t}/{len(today_t)} today",
                     font=("Segoe UI", 8), fg=C["text_dim"], bg=C["sidebar"]).pack(side="left")

            if self._check_plan_complete(plan):
                arch_btn = tk.Button(
                    sub, text="Archive ✓",
                    font=("Segoe UI", 8), bg=pcolor, fg="white",
                    relief="flat", padx=6, pady=1, cursor="hand2",
                    command=lambda p=plan: self._archive_plan(p),
                )
                arch_btn.pack(side="right")
            else:
                sched_btn = tk.Button(
                    sub, text="Schedule",
                    font=("Segoe UI", 8), bg=C["surface"], fg=C["text_dim"],
                    relief="flat", padx=6, pady=1, cursor="hand2",
                    command=lambda p=plan: self._show_schedule_dialog(p),
                )
                sched_btn.pack(side="right")

            if plan.get("briefing"):
                brief_btn = tk.Button(
                    sub, text="📋 Briefing",
                    font=("Segoe UI", 8), bg=C["surface"], fg=C["text_dim"],
                    relief="flat", padx=6, pady=1, cursor="hand2",
                    command=lambda p=plan: self._show_plan_briefing_dialog(p),
                )
                brief_btn.pack(side="right", padx=(0, 6))

        if len(self.plans) < MAX_PLANS:
            add_btn = tk.Button(
                self._plans_frame, text="+ Add Plan",
                font=("Segoe UI", 8), bg=C["surface"], fg=C["text_dim"],
                activebackground=C["surface"], activeforeground=C["text"],
                relief="flat", padx=8, pady=3, cursor="hand2",
                command=self._show_generate_plan_dialog,
            )
            add_btn.pack(anchor="w", pady=(6, 0))

        if hasattr(self, "_bind_sidebar_wheel"):
            self._bind_sidebar_wheel()

    # ── schedule dialog ───────────────────────────────────────────────────────

    def _show_schedule_dialog(self, plan):
        """Show all plan days with tasks; allow picking a future task to do today,
        or marking a day non-working (its tasks and everything after shift +1 day)."""
        plan_id = plan["id"]

        dlg = tk.Toplevel(self.root)
        dlg.title(f"Schedule — {plan['name']}")
        dlg.configure(bg=C["bg"])
        dlg.geometry("560x560")
        dlg.grab_set()

        # Header
        hdr_row = tk.Frame(dlg, bg=C["bg"])
        hdr_row.pack(fill="x")
        hdr_var = tk.StringVar()
        tk.Label(hdr_row, textvariable=hdr_var,
                 font=("Segoe UI", 12, "bold"), fg=C["text"], bg=C["bg"],
                 padx=20, pady=14).pack(side="left")

        def _edit_start_date():
            try:
                current = datetime.strptime(plan["start_date"], "%Y-%m-%d").date()
            except Exception:
                current = date.today()
            picked = self._pick_date_dialog(f"Start date for '{plan['name']}':", initial_date=current)
            if picked is None:
                return
            plan["start_date"] = picked.isoformat()
            self._save_plan(plan)
            self.render_tasks()
            self.tick_status()
            self._rebuild_plans_sidebar()
            _render_days()

        tk.Button(hdr_row, text="✏️ Edit start date", font=("Segoe UI", 8),
                  bg=C["surface"], fg=C["text_dim"], relief="flat", padx=8, pady=3,
                  cursor="hand2", command=_edit_start_date).pack(side="right", padx=20)

        tk.Label(dlg,
                 text='Click "Do today" on any future task to pull it to today.\n'
                      'Click "Day off" to push a day\'s tasks (and everything after) forward by one day.',
                 font=("Segoe UI", 9), fg=C["text_dim"], bg=C["bg"],
                 padx=20, justify="left").pack(anchor="w", pady=(0, 8))
        tk.Frame(dlg, bg=C["separator"], height=1).pack(fill="x")

        # Scrollable area
        canvas = tk.Canvas(dlg, bg=C["bg"], highlightthickness=0)
        scrollbar = tk.Scrollbar(dlg, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=scrollbar.set)
        scrollbar.pack(side="right", fill="y")
        canvas.pack(side="left", fill="both", expand=True)
        inner = tk.Frame(canvas, bg=C["bg"])
        win_id = canvas.create_window((0, 0), window=inner, anchor="nw")

        def _on_resize(e):
            canvas.itemconfig(win_id, width=e.width)
        canvas.bind("<Configure>", _on_resize)

        def _on_frame_resize(e):
            canvas.configure(scrollregion=canvas.bbox("all"))
        inner.bind("<Configure>", _on_frame_resize)

        def _scroll(e):
            canvas.yview_scroll(int(-1 * (e.delta / 120)), "units")

        def _bind_wheel(widget):
            widget.bind("<MouseWheel>", _scroll)
            for child in widget.winfo_children():
                _bind_wheel(child)

        def _do_today(p, task_text, task_original_day):
            self._swap_task_to_today(p, task_text, task_original_day)
            dlg.destroy()

        def _do_day_off(p, day):
            # One click reflows the whole plan tail — spell out the consequences
            # and get a yes before touching anything.
            by_day  = self._tasks_by_day_for(p)
            n_day   = len(by_day.get(day, []))
            n_after = sum(len(ts) for d, ts in by_day.items() if d > day)
            try:
                start = datetime.strptime(p["start_date"], "%Y-%m-%d").date()
                cal   = (start + timedelta(days=day - 1)).strftime("%d.%m.%Y")
                day_lbl = f"Day {day} ({cal})"
            except Exception:
                day_lbl = f"Day {day}"
            if not messagebox.askyesno(
                APP_NAME,
                f"Mark {day_lbl} as a day off?\n\n"
                f"{n_day} task(s) that day and {n_after} task(s) after it "
                f"will all shift one day later.\n\n"
                f"You can undo this from the same row.",
                parent=dlg,
            ):
                return
            self._mark_day_off(p, day)
            _render_days()

        def _undo_day_off(p, day):
            self._unmark_day_off(p, day)
            _render_days()

        def _render_days():
            for child in inner.winfo_children():
                child.destroy()

            pday      = self._plan_day_for(plan)
            by_day    = self._tasks_by_day_for(plan)
            total     = self._total_days_for(plan)
            days_off  = self._days_off_for(plan_id)
            hdr_var.set(f"{plan['name']}  ·  Day {pday} of {total}")

            days = sorted(set(by_day.keys()) | {pday} | days_off)
            for day in days:
                tasks = by_day.get(day, [])
                is_off = day in days_off
                if not tasks and not is_off:
                    continue
                is_today = (day == pday)
                is_past  = (day < pday)

                hdr_bg = C["surface"] if is_today else C["bg"]
                hdr_fg = plan.get("color", C["accent_blue"]) if is_today else C["text_dim"]
                suffix = " · DAY OFF" if is_off else (" ← TODAY" if is_today else (" (past)" if is_past else ""))
                label  = f"Day {day}{suffix}"

                hdr_f = tk.Frame(inner, bg=hdr_bg, padx=16, pady=6)
                hdr_f.pack(fill="x", pady=(8, 0))
                tk.Label(hdr_f, text=label, font=("Segoe UI", 9, "bold"),
                         fg=(C["accent_purple"] if is_off else hdr_fg), bg=hdr_bg).pack(side="left")

                if not is_past and not is_off:
                    tk.Button(
                        hdr_f, text="Day off",
                        font=("Segoe UI", 8), bg=C["surface"], fg=C["text_dim"],
                        relief="flat", padx=8, pady=2, cursor="hand2",
                        command=lambda d=day, p=plan: _do_day_off(p, d),
                    ).pack(side="right")
                elif is_off and not is_past:
                    tk.Button(
                        hdr_f, text="Undo day off",
                        font=("Segoe UI", 8), bg=C["surface"], fg=C["accent_purple"],
                        relief="flat", padx=8, pady=2, cursor="hand2",
                        command=lambda d=day, p=plan: _undo_day_off(p, d),
                    ).pack(side="right")

                for t in tasks:
                    task_text    = t.get("task", "")
                    orig_day     = t.get("original_day", day)
                    is_done      = self.completions.get((plan_id, day, task_text), False)

                    row_f = tk.Frame(inner, bg=C["bg"], padx=24, pady=3)
                    row_f.pack(fill="x")

                    dur = t.get("duration_min")
                    dur_txt = f" · {dur}m" if dur else ""
                    style = ("Segoe UI", 10)
                    col   = C["text_done"] if is_done else (C["text_muted"] if is_past else C["text"])
                    txt   = f"{'✓ ' if is_done else ''}{task_text}{dur_txt}"
                    tk.Label(row_f, text=txt, font=style, fg=col, bg=C["bg"],
                             anchor="w", justify="left", wraplength=380).pack(side="left", fill="x", expand=True)

                    if not is_done and not is_past and day > pday:
                        tk.Button(
                            row_f, text="Do today",
                            font=("Segoe UI", 8), bg=plan.get("color", C["accent_blue"]),
                            fg="white", relief="flat", padx=8, pady=2, cursor="hand2",
                            command=lambda tt=task_text, od=orig_day, p=plan: _do_today(p, tt, od),
                        ).pack(side="right", padx=(8, 0))

            # Mouse wheel scroll — bind on this dialog's widgets only, not bind_all,
            # so it doesn't clobber the main window's global mousewheel scroll binding.
            _bind_wheel(inner)

        _render_days()
        canvas.bind("<MouseWheel>", _scroll)
        self._finalize_dialog(dlg)

    def _reassign_task_day(self, plan_id, task_text, original_day, old_assigned_day, new_assigned_day):
        """Move one task to a new assigned day, migrating its completion record
        (keyed on assigned day) so a done/undone mark isn't lost in the move."""
        self._save_override(plan_id, task_text, original_day, new_assigned_day)
        old_key = (plan_id, old_assigned_day, task_text)
        new_key = (plan_id, new_assigned_day, task_text)
        if old_key in self.completions:
            self.completions[new_key] = self.completions.pop(old_key)

    def _swap_task_to_today(self, plan, target_task_text, target_original_day):
        """Pull a future task to today; shift everything between forward by +1 day."""
        plan_id  = plan["id"]
        today    = self._plan_day_for(plan)
        by_day   = self._tasks_by_day_for(plan)

        # The target task's current assigned day
        target_assigned = next(
            (t["day"] for tasks in by_day.values() for t in tasks
             if t.get("task") == target_task_text),
            target_original_day,
        )
        if target_assigned <= today:
            return  # already today or past

        # Collect all tasks
        all_tasks = [
            t for tasks in by_day.values() for t in tasks
        ]

        # Shift tasks assigned in [today, target_assigned) forward by 1
        for t in all_tasks:
            txt      = t.get("task", "")
            orig     = t.get("original_day", t["day"])
            assigned = t["day"]
            if txt == target_task_text:
                continue
            if today <= assigned < target_assigned:
                self._reassign_task_day(plan_id, txt, orig, assigned, assigned + 1)

        # Move target to today
        self._reassign_task_day(plan_id, target_task_text, target_original_day, target_assigned, today)

        self.render_tasks()
        self._rebuild_plans_sidebar()

    def _mark_day_off(self, plan, day):
        """Mark `day` as non-working: every task assigned on or after that day
        shifts forward by one day, leaving `day` free."""
        plan_id = plan["id"]
        by_day  = self._tasks_by_day_for(plan)
        all_tasks = [t for tasks in by_day.values() for t in tasks]

        for t in all_tasks:
            txt      = t.get("task", "")
            orig     = t.get("original_day", t["day"])
            assigned = t["day"]
            if assigned < day:
                continue
            self._reassign_task_day(plan_id, txt, orig, assigned, assigned + 1)

        self._mark_day_off_record(plan_id, day)
        self.render_tasks()
        self._rebuild_plans_sidebar()

    def _unmark_day_off(self, plan, day):
        """Inverse of _mark_day_off: shift every task assigned after `day` back
        by one day and clear the day-off record."""
        plan_id = plan["id"]
        by_day  = self._tasks_by_day_for(plan)
        all_tasks = [t for tasks in by_day.values() for t in tasks]

        for t in all_tasks:
            txt      = t.get("task", "")
            orig     = t.get("original_day", t["day"])
            assigned = t["day"]
            if assigned <= day:
                continue
            self._reassign_task_day(plan_id, txt, orig, assigned, assigned - 1)

        self.conn.execute(
            "DELETE FROM plan_days_off WHERE plan_id=? AND day=?", (plan_id, day)
        )
        self.conn.commit()
        self.render_tasks()
        self._rebuild_plans_sidebar()

    def _pick_date_dialog(self, title, min_date=None, initial_date=None):
        """Modal month-grid calendar picker. Returns a date, or None if cancelled.
        Days before min_date (if given) are shown disabled. If initial_date is
        given, the calendar opens on that month and highlights that date
        (e.g. an existing value being edited) distinctly from today."""
        import calendar as _calendar_mod

        result = {"date": None}
        today = date.today()
        view = {"year": today.year, "month": today.month}
        if initial_date:
            view["year"], view["month"] = initial_date.year, initial_date.month
        elif min_date and (min_date.year, min_date.month) > (today.year, today.month):
            view["year"], view["month"] = min_date.year, min_date.month

        dlg = tk.Toplevel(self.root)
        dlg.title(title)
        dlg.configure(bg=C["bg"])
        dlg.resizable(False, False)
        dlg.grab_set()

        tk.Label(dlg, text=title, font=("Segoe UI", 10, "bold"),
                 fg=C["text"], bg=C["bg"], wraplength=260,
                 justify="left").pack(padx=16, pady=(14, 6), anchor="w")

        hdr = tk.Frame(dlg, bg=C["bg"], padx=16)
        hdr.pack(fill="x")
        month_var = tk.StringVar()

        grid_frame = tk.Frame(dlg, bg=C["bg"], padx=16)
        grid_frame.pack(pady=(6, 4))

        def _pick(d):
            result["date"] = d
            dlg.destroy()

        def _render_month():
            for w in grid_frame.winfo_children():
                w.destroy()
            y, m = view["year"], view["month"]
            month_var.set(f"{_calendar_mod.month_name[m]} {y}")

            for i, wd in enumerate(("Mo", "Tu", "We", "Th", "Fr", "Sa", "Su")):
                tk.Label(grid_frame, text=wd, font=("Segoe UI", 8, "bold"),
                         fg=C["text_muted"], bg=C["bg"], width=4).grid(row=0, column=i, pady=(0, 4))

            for r, week in enumerate(_calendar_mod.Calendar(firstweekday=0).monthdayscalendar(y, m), start=1):
                for c, day_num in enumerate(week):
                    if day_num == 0:
                        tk.Label(grid_frame, text="", bg=C["bg"], width=4).grid(row=r, column=c, pady=1, padx=1)
                        continue
                    d = date(y, m, day_num)
                    disabled = min_date is not None and d < min_date
                    is_current_value = initial_date is not None and d == initial_date
                    bg = C["accent_blue"] if is_current_value else (C["surface"] if d == today else C["bg"])
                    fg = "white" if is_current_value else (C["text_muted"] if disabled else C["text"])
                    tk.Button(
                        grid_frame, text=str(day_num), font=("Segoe UI", 9), width=4,
                        fg=fg, bg=bg,
                        relief="flat", activebackground=C["accent_blue"], activeforeground="white",
                        state="disabled" if disabled else "normal",
                        command=None if disabled else (lambda dd=d: _pick(dd)),
                    ).grid(row=r, column=c, pady=1, padx=1)

        def _shift_month(delta):
            m = view["month"] + delta
            y = view["year"]
            if m < 1:
                m, y = 12, y - 1
            elif m > 12:
                m, y = 1, y + 1
            view["month"], view["year"] = m, y
            _render_month()

        prev_btn = tk.Button(hdr, text="<", font=("Segoe UI", 10), width=3, relief="flat",
                             bg=C["surface"], fg=C["text"], command=lambda: _shift_month(-1))
        prev_btn.pack(side="left")
        tk.Label(hdr, textvariable=month_var, font=("Segoe UI", 11, "bold"),
                 fg=C["text"], bg=C["bg"], width=16, anchor="center").pack(side="left", expand=True)
        next_btn = tk.Button(hdr, text=">", font=("Segoe UI", 10), width=3, relief="flat",
                             bg=C["surface"], fg=C["text"], command=lambda: _shift_month(1))
        next_btn.pack(side="left")
        Hovertip(prev_btn, "Previous month")
        Hovertip(next_btn, "Next month")

        _render_month()

        tk.Button(dlg, text="Cancel", font=("Segoe UI", 9), relief="flat",
                  bg=C["surface"], fg=C["text"], padx=12,
                  command=dlg.destroy).pack(pady=(4, 14))

        self._finalize_dialog(dlg)
        dlg.wait_window()
        return result["date"]

    def _reschedule_task_dialog(self, task, plan_id):
        """Pick a specific future date for one overdue task. Unlike 'Day off' or
        'Do today', this moves only this task and doesn't shift anything else —
        the overdue penalty already accrued for the days it was late stands."""
        plan = next((p for p in self.plans if p["id"] == plan_id), None)
        if not plan:
            return
        task_text = task.get("task", "")
        orig_day  = task.get("original_day", task.get("day"))
        old_day   = task.get("day")

        try:
            start = datetime.strptime(plan["start_date"], "%Y-%m-%d").date()
        except Exception:
            return
        pday = self._plan_day_for(plan)
        min_date = start + timedelta(days=pday)  # tomorrow (day pday+1)

        new_date = self._pick_date_dialog(f"Reschedule '{task_text}' to:", min_date=min_date)
        if new_date is None:
            return
        new_day = (new_date - start).days + 1

        self._reassign_task_day(plan_id, task_text, orig_day, old_day, new_day)

        self.render_tasks()
        self._rebuild_plans_sidebar()

    # ── task list area ────────────────────────────────────────────────────────

    def _build_task_list_area(self, parent):
        area = tk.Frame(parent, bg=C["bg"])
        area.pack(side="left", fill="both", expand=True)

        # List header
        list_hdr = tk.Frame(area, bg=C["bg"], padx=24, pady=18)
        list_hdr.pack(fill="x")
        self.list_title_var = tk.StringVar(value="Today")
        tk.Label(list_hdr, textvariable=self.list_title_var,
                 font=("Segoe UI", 20, "bold"), fg=C["text"], bg=C["bg"]).pack(side="left")
        self.date_var = tk.StringVar()
        tk.Label(list_hdr, textvariable=self.date_var, font=("Segoe UI", 9),
                 fg=C["text_muted"], bg=C["bg"]).pack(side="right", anchor="s", pady=(0, 4))

        tk.Frame(area, bg=C["separator"], height=1).pack(fill="x")

        body = tk.Frame(area, bg=C["bg"])
        body.pack(fill="both", expand=True)

        self.canvas = tk.Canvas(body, highlightthickness=0, bg=C["bg"])
        vsb = tk.Scrollbar(body, orient="vertical", command=self.canvas.yview)
        self.canvas.configure(yscrollcommand=vsb.set)
        vsb.pack(side="right", fill="y")
        self.canvas.pack(side="left", fill="both", expand=True)

        self.task_frame = tk.Frame(self.canvas, bg=C["bg"])
        self._win_id = self.canvas.create_window((0, 0), window=self.task_frame, anchor="nw")

        self.task_frame.bind("<Configure>",
                             lambda e: self.canvas.configure(scrollregion=self.canvas.bbox("all")))
        self.canvas.bind("<Configure>",
                         lambda e: self.canvas.itemconfigure(self._win_id, width=e.width))
        self.canvas.bind_all("<MouseWheel>",
                             lambda e: self.canvas.yview_scroll(int(-1 * (e.delta / 120)), "units"))

    # ── detail panel ─────────────────────────────────────────────────────────

    def _build_detail_panel(self, parent):
        dp = tk.Frame(parent, bg=C["bg"], width=280)
        dp.pack(side="left", fill="y")
        dp.pack_propagate(False)
        self._detail_panel = dp
        self._detail_inner = None
        self._show_detail_empty()

    def _show_detail_empty(self):
        self._detail_task = None
        if self._detail_inner:
            self._detail_inner.destroy()
        self._detail_inner = tk.Frame(self._detail_panel, bg=C["bg"])
        self._detail_inner.pack(fill="both", expand=True)
        tk.Label(self._detail_inner, text="Select a task",
                 font=("Segoe UI", 11), fg=C["text_muted"], bg=C["bg"]).pack(expand=True)

    def _show_task_detail(self, task, task_day, plan_id=None):
        self._detail_task = (task, task_day, plan_id)
        if self._detail_inner:
            self._detail_inner.destroy()
        self._detail_inner = tk.Frame(self._detail_panel, bg=C["bg"])
        self._detail_inner.pack(fill="both", expand=True)

        inner = tk.Frame(self._detail_inner, bg=C["bg"], padx=20, pady=20)
        inner.pack(fill="both", expand=True)

        category = task.get("category", "")
        duration = task.get("duration_min")
        detail   = task.get("detail", "")
        title    = task.get("task", "Untitled")
        is_ov    = task.get("overdue", False)

        # Category badge
        badge = "  ·  ".join(filter(None, [f"Day {task_day}", category.upper() if category else ""]))
        cat_color = CATEGORY_COLORS.get(category, C["text_muted"])
        tk.Label(inner, text=badge, font=("Segoe UI", 8, "bold"),
                 fg=cat_color, bg=C["bg"]).pack(anchor="w")

        tk.Label(inner, text=title, font=("Segoe UI", 14, "bold"),
                 fg=C["text_overdue"] if is_ov else C["text"],
                 bg=C["bg"], wraplength=240, justify="left").pack(anchor="w", pady=(8, 0))

        if duration:
            tk.Label(inner, text=f"⏱  {duration} min", font=("Segoe UI", 9),
                     fg=C["text_dim"], bg=C["bg"]).pack(anchor="w", pady=(6, 0))

        tk.Frame(inner, bg=C["separator"], height=1).pack(fill="x", pady=14)

        if detail:
            tk.Label(inner, text=detail, font=("Segoe UI", 10),
                     fg=C["text_dim"], bg=C["bg"], wraplength=240, justify="left").pack(anchor="w")
        else:
            tk.Label(inner, text="No details.", font=("Segoe UI", 10),
                     fg=C["text_muted"], bg=C["bg"]).pack(anchor="w")

        mentor_note = task.get("mentor_note", "")
        if mentor_note:
            tk.Label(inner, text="💡 Mentor's note", font=("Segoe UI", 9, "bold"),
                     fg=C["text_dim"], bg=C["bg"]).pack(anchor="w", pady=(14, 2))
            tk.Label(inner, text=mentor_note, font=("Segoe UI", 10),
                     fg=C["accent_blue"], bg=C["bg"], wraplength=240, justify="left").pack(anchor="w")

        if plan_id:
            tk.Button(
                inner, text="Edit", font=("Segoe UI", 9),
                bg=C["surface"], fg=C["text"], relief="flat", padx=10, pady=4,
                cursor="hand2",
                command=lambda: self._edit_task_dialog(task, task_day, plan_id),
            ).pack(anchor="w", pady=(16, 0))

    def _find_plan_task(self, plan, original_day, task_text):
        """Return a live reference to the task dict inside plan['phases'], so
        edits persist when the plan is saved back to disk."""
        for phase in plan.get("phases", []):
            for t in phase.get("tasks", []):
                if int(t.get("day", 0)) == original_day and t.get("task", "") == task_text:
                    return t
        return None

    def _edit_task_dialog(self, task, task_day, plan_id):
        plan = next((p for p in self.plans if p["id"] == plan_id), None)
        if not plan:
            return
        orig_day = task.get("original_day", task_day)
        old_text = task.get("task", "")
        target = self._find_plan_task(plan, orig_day, old_text)
        if target is None:
            messagebox.showerror(APP_NAME, "Could not locate this task in the plan file.", parent=self.root)
            return

        dlg = tk.Toplevel(self.root)
        dlg.title("Edit Task")
        dlg.configure(bg=C["bg"])
        dlg.resizable(False, False)
        dlg.grab_set()

        outer = tk.Frame(dlg, bg=C["bg"], padx=24, pady=20)
        outer.pack(fill="both", expand=True)

        def _label(text):
            tk.Label(outer, text=text, font=("Segoe UI", 9, "bold"),
                     fg=C["text_dim"], bg=C["bg"]).pack(anchor="w", pady=(10, 3))

        _label("Title")
        title_var = tk.StringVar(value=target.get("task", ""))
        tk.Entry(outer, textvariable=title_var, font=("Segoe UI", 10),
                 bg=C["surface"], fg=C["text"], insertbackground=C["text"],
                 relief="flat", bd=4, width=38).pack(fill="x")

        _label("Detail")
        detail_txt = tk.Text(outer, height=5, font=("Segoe UI", 10), wrap="word",
                              bg=C["surface"], fg=C["text"], insertbackground=C["text"],
                              relief="flat", bd=4)
        detail_txt.insert("1.0", target.get("detail", ""))
        detail_txt.pack(fill="x")

        _label("Mentor's note")
        mentor_note_txt = tk.Text(outer, height=3, font=("Segoe UI", 10), wrap="word",
                                   bg=C["surface"], fg=C["text"], insertbackground=C["text"],
                                   relief="flat", bd=4)
        mentor_note_txt.insert("1.0", target.get("mentor_note", ""))
        mentor_note_txt.pack(fill="x")

        row2 = tk.Frame(outer, bg=C["bg"])
        row2.pack(fill="x", pady=(14, 0))
        tk.Label(row2, text="Duration (min)", font=("Segoe UI", 9, "bold"),
                 fg=C["text_dim"], bg=C["bg"]).pack(side="left")
        dur_var = tk.StringVar(value=str(target.get("duration_min") or ""))
        tk.Entry(row2, textvariable=dur_var, width=8, font=("Segoe UI", 10),
                 bg=C["surface"], fg=C["text"], insertbackground=C["text"],
                 relief="flat", bd=4).pack(side="left", padx=(10, 0))

        _label("Category")
        cat_var = tk.StringVar(value=target.get("category", ""))
        cat_dd = tk.OptionMenu(outer, cat_var, "", *CATEGORY_COLORS.keys())
        cat_dd.configure(bg=C["surface"], fg=C["text"], font=("Segoe UI", 10),
                         relief="flat", highlightthickness=0)
        cat_dd.pack(fill="x")

        err_var = tk.StringVar()
        tk.Label(outer, textvariable=err_var, font=("Segoe UI", 9),
                 fg=C["accent_red"], bg=C["bg"]).pack(anchor="w", pady=(10, 0))

        def _save():
            new_title = title_var.get().strip()
            if not new_title:
                err_var.set("Title can't be empty.")
                return
            dur_raw = dur_var.get().strip()
            new_dur = None
            if dur_raw:
                try:
                    new_dur = int(dur_raw)
                except ValueError:
                    err_var.set("Duration must be a whole number of minutes.")
                    return
            new_detail = detail_txt.get("1.0", "end").strip()
            new_mentor_note = mentor_note_txt.get("1.0", "end").strip()
            new_cat = cat_var.get().strip()
            self._apply_task_edit(plan, target, old_text, new_title, new_detail,
                                   new_mentor_note, new_dur, new_cat)
            dlg.destroy()

        btn_row = tk.Frame(outer, bg=C["bg"])
        btn_row.pack(fill="x", pady=(18, 0))
        tk.Button(btn_row, text="Cancel", font=("Segoe UI", 10),
                  bg=C["surface"], fg=C["text"], relief="flat", padx=12,
                  command=dlg.destroy).pack(side="right", padx=(8, 0))
        tk.Button(btn_row, text="Save", font=("Segoe UI", 10),
                  bg=plan.get("color", C["accent_blue"]), fg="white", relief="flat", padx=12,
                  command=_save).pack(side="right")

        self._finalize_dialog(dlg)

    def _apply_task_edit(self, plan, target, old_text, new_title, new_detail,
                          new_mentor_note, new_dur, new_cat):
        """Mutate the task in-place in the plan JSON and, if the title changed,
        migrate every DB row keyed on the old title so completion history and
        the TickTick mapping stay attached to the (renamed) task."""
        plan_id = plan["id"]
        target["task"] = new_title
        target["detail"] = new_detail
        if new_mentor_note:
            target["mentor_note"] = new_mentor_note
        else:
            target.pop("mentor_note", None)
        if new_dur is not None:
            target["duration_min"] = new_dur
        else:
            target.pop("duration_min", None)
        if new_cat:
            target["category"] = new_cat
        else:
            target.pop("category", None)
        self._save_plan(plan)

        if new_title != old_text:
            self.conn.execute(
                "UPDATE task_completions SET task_text=? WHERE plan_id=? AND task_text=?",
                (new_title, plan_id, old_text),
            )
            self.conn.execute(
                "UPDATE task_overrides SET task_text=? WHERE plan_id=? AND task_text=?",
                (new_title, plan_id, old_text),
            )
            self.conn.execute(
                "UPDATE ticktick_sync SET task_text=? WHERE task_text=?",
                (new_title, old_text),
            )
            self.conn.commit()
            for key in list(self.completions.keys()):
                if key[0] == plan_id and key[2] == old_text:
                    self.completions[(key[0], key[1], new_title)] = self.completions.pop(key)

        self._show_detail_empty()
        self.render_tasks()
        self._rebuild_plans_sidebar()

    # ── plan task rendering ──────────────────────────────────────────────────

    def _display_tasks_for(self, plan):
        pid    = plan["id"]
        pday   = self._plan_day_for(plan)
        by_day = self._tasks_by_day_for(plan)
        if pday <= 0:
            return []
        today_tasks = [dict(t) for t in by_day.get(pday, [])]
        overdue = []
        for day in sorted(by_day):
            if day >= pday:
                continue
            for t in by_day[day]:
                if not self.completions.get((pid, day, t.get("task", "")), False):
                    item = dict(t)
                    item["day"] = day
                    item["overdue"] = True
                    overdue.append(item)
        for t in today_tasks:
            t.setdefault("day", pday)
            t.setdefault("overdue", False)
            t.setdefault("early", False)

        early_tasks = []
        if pid in self._early_plans:
            for t in by_day.get(pday + 1, []):
                item = dict(t)
                item["day"]    = pday + 1
                item["overdue"] = False
                item["early"]   = True
                early_tasks.append(item)

        return overdue + today_tasks + early_tasks

    def _render_section_header(self, label, accent=None):
        accent = accent or C["text_muted"]
        wrap = tk.Frame(self.task_frame, bg=C["bg"])
        wrap.pack(fill="x", padx=24, pady=(18, 0))
        tk.Frame(wrap, bg=accent, height=2).pack(fill="x")
        tk.Label(wrap, text=label, font=("Segoe UI", 11, "bold"),
                 fg=accent, bg=C["bg"]).pack(anchor="w", pady=(4, 2))

    def _render_subsection_label(self, label, color):
        lbl = tk.Label(self.task_frame, text=label, font=("Segoe UI", 8, "bold"),
                       fg=color, bg=C["bg"], padx=24)
        lbl.pack(anchor="w", pady=(6, 2))
        return lbl

    def render_tasks(self):
        try:
            self._render_tasks_unsafe()
        except Exception:
            import logging
            logging.critical("render_tasks failed", exc_info=True)
            for child in self.task_frame.winfo_children():
                child.destroy()
            tk.Label(
                self.task_frame,
                text="Something went wrong showing today's tasks.\nSee data/mentor.log for details.",
                font=("Segoe UI", 11), fg=C["text_muted"], bg=C["bg"],
                padx=24, pady=24, justify="left",
            ).pack(anchor="w")
            tk.Button(
                self.task_frame, text="Retry", font=("Segoe UI", 9),
                bg=C["surface"], fg=C["text"], relief="flat", padx=10,
                command=self.render_tasks,
            ).pack(anchor="w", padx=24)

    def _render_tasks_unsafe(self):
        for child in self.task_frame.winfo_children():
            child.destroy()
        self.task_vars.clear()
        self._first_overdue_widget = None  # scroll anchor for the Overdue nav item

        if not self.plans:
            empty = tk.Frame(self.task_frame, bg=C["bg"])
            empty.pack(anchor="w", padx=24, pady=24)
            tk.Label(empty, text="No active plans yet.",
                     font=("Segoe UI", 12), bg=C["bg"], fg=C["text"]).pack(anchor="w")
            tk.Label(empty,
                     text="Generate one with Claude, paste your own, or load a plan file.",
                     font=("Segoe UI", 10), bg=C["bg"], fg=C["text_dim"]).pack(anchor="w", pady=(4, 0))
            tk.Button(empty, text="+ Add Plan", font=("Segoe UI", 10),
                      bg=C["accent_blue"], fg="white",
                      activebackground=C["accent_blue_active"], activeforeground="white",
                      relief="flat", padx=14, pady=5, cursor="hand2",
                      command=self._show_generate_plan_dialog).pack(anchor="w", pady=(12, 0))
            self._render_ticktick_section()
            return

        for plan in self.plans:
            pid    = plan["id"]
            pday   = self._plan_day_for(plan)
            ptotal = self._total_days_for(plan)
            pname  = plan["name"]

            tasks   = self._display_tasks_for(plan)
            overdue = [t for t in tasks if t.get("overdue")]
            today   = [t for t in tasks if not t.get("overdue") and not t.get("early")]
            early   = [t for t in tasks if t.get("early")]
            done_n  = sum(
                1 for t in today
                if self.completions.get((pid, t.get("day", pday), t.get("task", "")), False)
            )

            if pday <= 0:
                days_away = abs(pday - 1)
                self._render_section_header(pname, C["text"])
                tk.Label(self.task_frame,
                         text=f"Starts {self._fmt_date(plan['start_date'])} — {days_away} day(s) to go.",
                         font=("Segoe UI", 10), bg=C["bg"], fg=C["text_dim"],
                         padx=24, pady=8).pack(anchor="w")
                continue

            header = f"{pname}  ·  Day {pday} of {ptotal}"
            self._render_section_header(header, C["text"])

            if overdue:
                ov_lbl = self._render_subsection_label(f"Overdue · {len(overdue)}", C["accent_red"])
                if self._first_overdue_widget is None:
                    self._first_overdue_widget = ov_lbl
                for task in overdue:
                    self._render_plan_row(task, pid)

            if today:
                self._render_subsection_label(f"Today · {done_n}/{len(today)}", C["text_dim"])
                for task in today:
                    self._render_plan_row(task, pid)
            elif not overdue:
                tk.Label(self.task_frame, text="All done for today — great work!",
                         font=("Segoe UI", 10), bg=C["bg"], fg=C["text_muted"],
                         padx=24, pady=6).pack(anchor="w")

            if early:
                self._render_subsection_label(
                    f"Early start · Day {pday + 1}  ({len(early)} tasks)", C["accent_purple"]
                )
                for task in early:
                    self._render_plan_row(task, pid)

        self._render_ticktick_section()

    def _row_hover(self, row, enter):
        bg = C["hover"] if enter else C["bg"]
        row.config(bg=bg)
        for w in row.winfo_children():
            try: w.config(bg=bg)
            except Exception: pass

    def _render_plan_row(self, task, plan_id):
        task_day   = task.get("day", self.plan_day)
        is_overdue = task.get("overdue", False)
        title      = task.get("task", "Untitled")
        category   = task.get("category", "")
        duration   = task.get("duration_min")
        key        = (plan_id, task_day, title)

        is_done = self.completions.get(key, False)
        var = tk.BooleanVar(value=is_done)
        self.task_vars[key] = var

        # takefocus puts the row in the Tab order; the highlight ring doubles as
        # the visible focus state (invisible until focused — bg-on-bg).
        row = tk.Frame(self.task_frame, bg=C["bg"], pady=2, cursor="hand2",
                       takefocus=1, highlightthickness=1,
                       highlightbackground=C["bg"], highlightcolor=C["accent_blue"])
        row.pack(fill="x")
        row.bind("<Enter>", lambda e, r=row: self._row_hover(r, True))
        row.bind("<Leave>", lambda e, r=row: self._row_hover(r, False))
        row.bind("<Button-1>", lambda e, t=task, d=task_day, pid=plan_id: self._show_task_detail(t, d, pid))
        row.bind("<Return>", lambda e, t=task, d=task_day, pid=plan_id: self._show_task_detail(t, d, pid))
        row.bind("<space>",
                 lambda e, k=key, v=var, pid=plan_id: (v.set(not v.get()),
                                                       self._on_plan_toggle(k, v, pid)))

        cb = tk.Checkbutton(
            row, variable=var,
            bg=C["bg"], fg=C["text"], selectcolor=C["check_sel"],
            activebackground=C["bg"], activeforeground=C["text"],
            command=lambda k=key, v=var, pid=plan_id: self._on_plan_toggle(k, v, pid),
        )
        cb.pack(side="left", padx=(24, 8), pady=10)

        text_col = tk.Frame(row, bg=C["bg"])
        text_col.pack(side="left", fill="x", expand=True, pady=10)
        text_col.bind("<Button-1>", lambda e, t=task, d=task_day, pid=plan_id: self._show_task_detail(t, d, pid))

        title_fg = C["text_done"] if is_done else (C["text_overdue"] if is_overdue else C["text"])
        tk.Label(text_col, text=title, font=("Segoe UI", 11),
                 fg=title_fg, bg=C["bg"], anchor="w", justify="left").pack(anchor="w")

        if category:
            dot = tk.Canvas(row, width=8, height=8, bg=C["bg"], highlightthickness=0)
            dot.create_oval(1, 1, 7, 7, fill=CATEGORY_COLORS.get(category, C["text_muted"]), outline="")
            dot.pack(side="right", padx=(4, 8))
            # Color must never be the only signal — name the category too.
            tk.Label(row, text=category, font=("Segoe UI", 8),
                     fg=C["text_muted"], bg=C["bg"]).pack(side="right")

        if duration and not is_done:
            tk.Label(row, text=f"{duration}m", font=("Segoe UI", 8),
                     fg=C["text_muted"], bg=C["bg"]).pack(side="right", padx=(0, 6))

        if is_overdue:
            tk.Button(
                row, text="Reschedule", font=("Segoe UI", 8),
                bg=C["surface"], fg=C["text_dim"], relief="flat", padx=8, pady=2,
                cursor="hand2",
                command=lambda t=task, pid=plan_id: self._reschedule_task_dialog(t, pid),
            ).pack(side="right", padx=(0, 6))

        tk.Frame(self.task_frame, bg=C["separator"], height=1).pack(fill="x", padx=24)

    def _check_early_prompt(self, plan_id, plan_day):
        plan = next((p for p in self.plans if p["id"] == plan_id), None)
        if not plan or plan_id in self._early_plans:
            return
        by_day = self._tasks_by_day_for(plan)
        today_tasks = by_day.get(plan_day, [])
        if not today_tasks:
            return
        all_done = all(
            self.completions.get((plan_id, plan_day, t.get("task", "")), False)
            for t in today_tasks
        )
        if all_done and by_day.get(plan_day + 1):
            next_count = len(by_day[plan_day + 1])
            answer = messagebox.askyesno(
                APP_NAME,
                f"All of today's tasks are done!\n\n"
                f"Get a head start on tomorrow's {next_count} task(s)?",
                parent=self.root,
            )
            if answer:
                self._early_plans.add(plan_id)
                self.render_tasks()

    def _on_plan_toggle(self, key, var, plan_id):
        is_done = var.get()
        _, plan_day, task_text = key
        self.save_completion(plan_id, plan_day, task_text, is_done)
        self.render_tasks()
        self.tick_status()
        self._rebuild_plans_sidebar()
        if is_done:
            self._check_early_prompt(plan_id, plan_day)

    # ── TickTick section in scroll area ─────────────────────────────────────

    def _render_ticktick_section(self):
        self._render_section_header("My Tasks  (TickTick)", C["text"])

        if not self.ticktick or not self.ticktick.is_authorized:
            wrap = tk.Frame(self.task_frame, bg=C["bg"])
            wrap.pack(anchor="w", padx=24, pady=4)
            tk.Label(wrap, text="Pull in your personal TickTick tasks due today.",
                     font=("Segoe UI", 10), fg=C["text_muted"], bg=C["bg"]).pack(anchor="w")
            if self.ticktick:  # still None while the client initialises
                tk.Button(wrap, text="Connect TickTick", font=("Segoe UI", 9),
                          bg=C["surface"], fg=C["text_dim"],
                          activebackground=C["hover"], activeforeground=C["text"],
                          relief="flat", padx=10, pady=3, cursor="hand2",
                          command=self.on_connect_ticktick).pack(anchor="w", pady=(6, 0))
            return

        if not self.tt_tasks:
            tk.Label(self.task_frame, text="No personal TickTick tasks due today.",
                     font=("Segoe UI", 10), fg=C["text_muted"], bg=C["bg"],
                     padx=24, pady=4).pack(anchor="w")
            return

        for tt_task in self.tt_tasks:
            self._render_ticktick_row(tt_task)

    def _render_ticktick_row(self, tt_task):
        task_id    = tt_task.get("id", "")
        project_id = tt_task.get("projectId", "")
        proj_name  = tt_task.get("_projectName", "")
        title      = tt_task.get("title", "Untitled")
        due        = self._fmt_date((tt_task.get("dueDate") or "")[:10])

        row = tk.Frame(self.task_frame, bg=C["bg"], pady=2, cursor="hand2")
        row.pack(fill="x")
        row.bind("<Enter>", lambda e, r=row: self._row_hover(r, True))
        row.bind("<Leave>", lambda e, r=row: self._row_hover(r, False))

        var = tk.BooleanVar(value=False)
        tk.Checkbutton(
            row, variable=var,
            bg=C["bg"], fg=C["text"], selectcolor=C["check_sel"],
            activebackground=C["bg"], activeforeground=C["text"],
            command=lambda tid=task_id, v=var, r=row, pid=project_id: self._on_tt_toggle(tid, v, r, pid),
        ).pack(side="left", padx=(24, 8), pady=10)

        tk.Label(row, text=title, font=("Segoe UI", 11),
                 fg=C["text"], bg=C["bg"], anchor="w").pack(side="left", fill="x", expand=True, pady=10)

        dot = tk.Canvas(row, width=8, height=8, bg=C["bg"], highlightthickness=0)
        dot.create_oval(1, 1, 7, 7, fill=C["tt_badge"], outline="")
        dot.pack(side="right", padx=(4, 8))

        if due:
            tk.Label(row, text=due, font=("Segoe UI", 8),
                     fg=C["text_muted"], bg=C["bg"]).pack(side="right", padx=(0, 6))

        if proj_name:
            tk.Label(row, text=proj_name[:18], font=("Segoe UI", 8),
                     fg=C["text_muted"], bg=C["bg"]).pack(side="right", padx=(0, 6))

        tk.Frame(self.task_frame, bg=C["separator"], height=1).pack(fill="x", padx=24)

    def _on_tt_toggle(self, task_id, var, row, project_id):
        if not var.get():
            return
        # disable checkbox immediately
        for child in row.winfo_children():
            if isinstance(child, tk.Checkbutton):
                child.config(state="disabled")

        pid = project_id or self.tt_project_id

        def _complete():
            try:
                self.ticktick.complete_task(pid, task_id)
                self.root.after(0, lambda: self._tt_remove_task(task_id))
            except Exception as exc:
                # `except ... as exc` unbinds exc once the block exits, so the
                # lambda (which runs later via root.after) can't reference exc
                # itself — capture the message as a plain string now.
                msg = f"TickTick error: {exc}"
                self.root.after(0, lambda: self.tt_status_var.set(msg))

        threading.Thread(target=_complete, daemon=True).start()

    def _tt_remove_task(self, task_id):
        self.tt_tasks = [t for t in self.tt_tasks if t.get("id") != task_id]
        self.render_tasks()
        self.tt_status_var.set(
            f"TickTick: {len(self.tt_tasks)} open task(s) · updated {datetime.now().strftime('%H:%M')}"
        )

    # ── Activity tracker ─────────────────────────────────────────────────────

    def init_tracker(self):
        if not HAS_TRACKER:
            self._act_status_var.set("Unavailable")
            return
        self.tracker = ActivityTracker(
            config=self.config,
            db_path=DB_PATH,
            on_alert=self._on_tracker_alert,
            on_idle=self._on_idle_detected,
        )
        self.tracker.start()
        self._update_activity_status()
        self.root.after(2000, self._check_startup_gap)

    def _check_startup_gap(self):
        """On startup, ask about any untracked time since diary_start (06:00)."""
        from datetime import time as dtime
        now = datetime.now()
        diary_start_time = dtime(6, 0)
        diary_end_time   = dtime(20, 0)
        if not (diary_start_time <= now.time() <= diary_end_time):
            return
        diary_start_today = datetime.combine(now.date(), diary_start_time)

        # Determine the last time the app was active
        last_seen = None
        try:
            raw = _LAST_SEEN_PATH.read_text().strip()
            last_seen = datetime.fromisoformat(raw)
        except Exception:
            pass

        if last_seen and last_seen.date() == now.date():
            gap_start = last_seen
        else:
            # App wasn't running today yet — gap starts at 06:00
            gap_start = diary_start_today

        gap_min = int((now - gap_start).total_seconds() / 60)
        threshold = self.config.get("idle_threshold_minutes", 10)
        if gap_min < threshold:
            return

        # Check if the diary already has an entry covering this period
        try:
            cur = self.conn.cursor()
            cur.execute(
                "SELECT MAX(end_time) FROM time_diary WHERE date=?",
                (now.date().isoformat(),),
            )
            row = cur.fetchone()
            last_entry = row[0] if row and row[0] else None
        except Exception:
            last_entry = None

        if last_entry:
            try:
                h, m = (int(x) for x in last_entry.split(":")[:2])
                last_dt = datetime.combine(now.date(), dtime(h, m))
                gap_start = max(gap_start, last_dt)
                gap_min = int((now - gap_start).total_seconds() / 60)
                if gap_min < threshold:
                    return
            except Exception:
                pass

        self._show_idle_dialog(gap_min, gap_start.strftime("%Y-%m-%d %H:%M:%S"))

    def _on_tracker_alert(self, title, message):
        self.root.after(0, lambda t=title, m=message: self._notify(t, m))

    def _on_idle_detected(self, idle_minutes, idle_start_str):
        self.root.after(0, lambda: self._show_idle_dialog(idle_minutes, idle_start_str))

    def _show_idle_dialog(self, idle_minutes, idle_start_str):
        dlg = tk.Toplevel(self.root)
        dlg.title(APP_NAME)
        dlg.configure(bg=C["bg"])
        dlg.attributes("-topmost", True)
        dlg.resizable(False, True)
        def _dismiss():
            if self.tracker:
                self.tracker.log_idle_answer(idle_start_str, idle_minutes, "dismissed")
            dlg.grab_release()
            dlg.destroy()
            if self.root.state() != "withdrawn":
                self._show_report_view() if getattr(self, "_active_view", "") == "report" else None

        dlg.protocol("WM_DELETE_WINDOW", _dismiss)
        dlg.grab_set()

        w, h = 500, 320
        dlg.update_idletasks()
        sw = dlg.winfo_screenwidth()
        sh = dlg.winfo_screenheight()
        dlg.geometry(f"{w}x{h}+{(sw - w) // 2}+{(sh - h) // 2}")
        dlg.minsize(w, 260)

        outer = tk.Frame(dlg, bg=C["bg"], padx=28, pady=20)
        outer.pack(fill="both", expand=True)

        # Header
        tk.Label(outer, text=f"No activity for {idle_minutes} min",
                 font=("Segoe UI", 14, "bold"), fg=C["text"], bg=C["bg"]).pack(anchor="w")
        tk.Label(outer,
                 text="What were you doing? Add one row per activity — durations must total the idle time.",
                 font=("Segoe UI", 9), fg=C["text_dim"], bg=C["bg"],
                 wraplength=440, justify="left").pack(anchor="w", pady=(2, 12))

        # Column headers
        col_hdr = tk.Frame(outer, bg=C["bg"])
        col_hdr.pack(fill="x", pady=(0, 2))
        tk.Label(col_hdr, text="Min", font=("Segoe UI", 8, "bold"),
                 fg=C["text_muted"], bg=C["bg"], width=5, anchor="w").pack(side="left", padx=(0, 6))
        tk.Label(col_hdr, text="What you did", font=("Segoe UI", 8, "bold"),
                 fg=C["text_muted"], bg=C["bg"], anchor="w").pack(side="left")

        rows_frame = tk.Frame(outer, bg=C["bg"])
        rows_frame.pack(fill="x")

        # Bottom bar — created before _add_row so _update() can reference these
        btm = tk.Frame(outer, bg=C["bg"])
        btm.pack(fill="x", pady=(14, 0))

        counter_var = tk.StringVar(value="Fill in description")
        counter_lbl = tk.Label(btm, textvariable=counter_var, font=("Segoe UI", 9),
                               fg=C["accent_amber"], bg=C["bg"])
        counter_lbl.pack(side="left")

        submit_btn = tk.Button(btm, text="Submit",
                               font=("Segoe UI", 10, "bold"),
                               bg=C["accent_blue"], fg="white",
                               activebackground=C["accent_blue_active"], activeforeground="white",
                               relief="flat", padx=16, pady=5, state="disabled")
        submit_btn.pack(side="right", padx=(8, 0))

        add_btn = tk.Button(btm, text="+ Add activity", font=("Segoe UI", 9),
                            bg=C["bg"], fg=C["accent_blue"], relief="flat",
                            cursor="hand2", bd=0)
        add_btn.pack(side="right")

        # ── activity row management ──────────────────────────────────────────
        activity_rows = []   # list of dicts

        PLACEHOLDER = "e.g. lunch, walked the dog…"

        def _update():
            used = 0
            for r in activity_rows:
                try:
                    used += max(0, int(r["dur_var"].get() or "0"))
                except ValueError:
                    pass
            rem = idle_minutes - used

            all_dur_ok = all(
                r["dur_var"].get().strip().isdigit() and int(r["dur_var"].get()) > 0
                for r in activity_rows
            )
            all_desc_ok = all(
                bool(r["desc_entry"].get().strip()) and
                not r["desc_entry"].get().strip().startswith("e.g.")
                for r in activity_rows
            )

            if rem < 0:
                counter_var.set(f"{-rem} min over — reduce a duration")
                counter_lbl.config(fg=C["accent_red"])
            elif rem > 0 and all_dur_ok and all_desc_ok:
                counter_var.set(f"{rem} min unaccounted — OK to save")
                counter_lbl.config(fg=C["accent_amber"])
            elif not all_desc_ok:
                counter_var.set("Fill in all descriptions")
                counter_lbl.config(fg=C["accent_amber"])
            else:
                counter_var.set("All time accounted ✓")
                counter_lbl.config(fg=C["accent_green"])

            can_submit = (rem >= 0 and all_dur_ok and all_desc_ok)
            submit_btn.config(state="normal" if can_submit else "disabled")

            # remove buttons visible only when 2+ rows
            for r in activity_rows:
                r["remove_btn"].config(
                    state="normal" if len(activity_rows) > 1 else "disabled",
                    fg=C["text_muted"] if len(activity_rows) > 1 else C["text_muted"],
                )

        def _add_row(dur=None):
            frame = tk.Frame(rows_frame, bg=C["bg"])
            frame.pack(fill="x", pady=2)

            dur_var = tk.StringVar(value=str(dur) if dur is not None else "")
            dur_entry = tk.Entry(frame, textvariable=dur_var, width=5,
                                 font=("Segoe UI", 10), bg=C["surface"], fg=C["text"],
                                 insertbackground=C["text"], relief="flat", justify="right")
            dur_entry.pack(side="left", ipady=4, padx=(0, 6))
            tk.Label(frame, text="min", font=("Segoe UI", 9),
                     fg=C["text_muted"], bg=C["bg"]).pack(side="left", padx=(0, 8))

            desc_entry = tk.Entry(frame, font=("Segoe UI", 10),
                                  bg=C["surface"], fg=C["text_muted"],
                                  insertbackground=C["text"], relief="flat")
            desc_entry.pack(side="left", fill="x", expand=True, ipady=4)
            desc_entry.insert(0, PLACEHOLDER)

            row_data = {}

            def _remove():
                frame.destroy()
                activity_rows.remove(row_data)
                _update()

            remove_btn = tk.Button(frame, text="✕", font=("Segoe UI", 9),
                                   bg=C["bg"], fg=C["text_muted"], relief="flat",
                                   cursor="hand2", bd=0, command=_remove)
            remove_btn.pack(side="right", padx=(6, 0))
            Hovertip(remove_btn, "Remove this activity row")

            def _focus_in(e):
                if desc_entry.get() == PLACEHOLDER:
                    desc_entry.delete(0, "end")
                    desc_entry.config(fg=C["text"])

            def _focus_out(e):
                if not desc_entry.get().strip():
                    desc_entry.insert(0, PLACEHOLDER)
                    desc_entry.config(fg=C["text_muted"])

            desc_entry.bind("<FocusIn>",  _focus_in)
            desc_entry.bind("<FocusOut>", _focus_out)
            dur_var.trace_add("write", lambda *_: _update())
            desc_entry.bind("<KeyRelease>", lambda e: _update())

            row_data.update({
                "frame": frame, "dur_var": dur_var,
                "dur_entry": dur_entry, "desc_entry": desc_entry,
                "remove_btn": remove_btn,
            })
            activity_rows.append(row_data)
            _update()
            return row_data

        add_btn.config(command=_add_row)

        # Initial row pre-filled with total idle time
        first = _add_row(dur=idle_minutes)
        first["desc_entry"].focus_set()

        # ── submit ───────────────────────────────────────────────────────────

        def _submit():
            if submit_btn.cget("state") == "disabled":
                return
            entries = []
            for r in activity_rows:
                try:
                    dur = int(r["dur_var"].get().strip())
                except ValueError:
                    continue
                desc = r["desc_entry"].get().strip()
                if not desc or desc.startswith("e.g."):
                    continue
                if dur > 0:
                    entries.append((dur, desc))

            if self.tracker and entries:
                try:
                    t_cur = datetime.strptime(idle_start_str, "%Y-%m-%d %H:%M:%S")
                except Exception:
                    t_cur = datetime.now() - timedelta(minutes=idle_minutes)
                for dur, desc in entries:
                    self.tracker.log_idle_answer(
                        t_cur.strftime("%Y-%m-%d %H:%M:%S"), dur, desc
                    )
                    t_cur += timedelta(minutes=dur)

            dlg.grab_release()
            dlg.destroy()
            # Refresh report page if it was already open
            if getattr(self, "_active_view", "") == "report":
                self._show_report_view()

        submit_btn.config(command=_submit)
        dlg.bind("<Return>", lambda e: _submit())
        dlg.bind("<Escape>", lambda e: _dismiss())

    def _update_activity_status(self):
        if self.tracker:
            cls, window = self.tracker.status
            dot_color  = {"on_plan": C["accent_green"], "off_plan": C["accent_red"],
                          "paid": C["accent_purple"]}.get(cls, C["text_muted"])
            status_lbl = {"on_plan": "On Plan", "off_plan": "Off Plan",
                         "paid": "Paid Time"}.get(cls, "Neutral")
            self._act_dot.itemconfig(self._act_dot_item, fill=dot_color)
            self._act_status_var.set(status_lbl)
            # Show app name from window title (up to first dash or bracket)
            app = self._extract_app_name(window, 35)
            self._act_window_var.set(app)
            if cls == "off_plan":
                off = self.tracker.off_plan_minutes
                if off:
                    self._act_window_var.set(f"{app}  ·  {off}m off-plan")
        self._refresh_score_sidebar()
        self.root.after(30_000, self._update_activity_status)

    # ── score: sidebar, purchase & spend dialogs ────────────────────────────

    def _refresh_score_sidebar(self):
        for w in self._score_body.winfo_children():
            w.destroy()

        balance = self._score_balance()
        paid_until = self.tracker._paid_until if self.tracker else None
        active = paid_until and datetime.now() < paid_until

        if active:
            remaining = max(0, int((paid_until - datetime.now()).total_seconds() / 60) + 1)
            tk.Label(self._score_body, text=f"Paid time: {remaining}m left",
                     font=("Segoe UI", 10, "bold"), fg=C["accent_purple"],
                     bg=C["sidebar"]).pack(anchor="w")
            # Re-check when the window is due to expire so the sidebar flips
            # back to normal without waiting for the next 30s activity tick.
            self.root.after(min(30_000, (remaining + 1) * 60_000), self._refresh_score_sidebar)
        else:
            if paid_until:
                # Window just expired — clear it and let the tracker know.
                self.tracker.set_paid_until(None)
                self._notify(APP_NAME, "Paid time ended — back to normal scoring.")
            tk.Label(self._score_body, text=f"{balance} pts",
                     font=("Segoe UI", 14, "bold"), fg=C["text"],
                     bg=C["sidebar"]).pack(anchor="w", pady=(0, 6))

            _bs = dict(font=("Segoe UI", 9), bg=C["sidebar"], fg=C["text_dim"],
                       activebackground=C["surface"], activeforeground=C["text"],
                       relief="flat", anchor="w", padx=0, cursor="hand2", bd=0)
            tk.Button(self._score_body, text="Buy entertainment time",
                      command=self._show_buy_entertainment_dialog, **_bs).pack(fill="x", ipady=3)
            tk.Button(self._score_body, text="Log spend (no regrets)",
                      command=self._show_log_expenditure_dialog, **_bs).pack(fill="x", ipady=3)

        if hasattr(self, "_bind_sidebar_wheel"):
            self._bind_sidebar_wheel()

    def _show_buy_entertainment_dialog(self):
        rate, _, _ = self._score_rates()
        balance = self._score_balance()

        dlg = tk.Toplevel(self.root)
        dlg.title("Buy entertainment time")
        dlg.configure(bg=C["bg"])
        dlg.resizable(False, False)
        dlg.grab_set()

        tk.Label(dlg, text=f"Balance: {balance} pts   ·   rate: {rate} pt/min",
                 font=("Segoe UI", 9), fg=C["text_dim"], bg=C["bg"]
                 ).pack(padx=20, pady=(16, 8), anchor="w")

        row = tk.Frame(dlg, bg=C["bg"])
        row.pack(padx=20, fill="x")
        tk.Label(row, text="Minutes:", width=10, anchor="w",
                 bg=C["bg"], fg=C["text"]).pack(side="left")
        minutes_var = tk.StringVar(value="30")
        tk.Entry(row, textvariable=minutes_var, width=10,
                 bg=C["surface"], fg=C["text"], insertbackground=C["text"],
                 relief="flat").pack(side="left")

        cost_var = tk.StringVar()

        def _update_cost(*_):
            try:
                m = float(minutes_var.get())
                cost_var.set(f"Cost: {int(round(m * rate))} pts")
            except ValueError:
                cost_var.set("Cost: —")

        minutes_var.trace_add("write", _update_cost)
        _update_cost()
        tk.Label(dlg, textvariable=cost_var, font=("Segoe UI", 9),
                 fg=C["text_dim"], bg=C["bg"]).pack(padx=20, pady=(6, 0), anchor="w")

        def _confirm():
            try:
                minutes = float(minutes_var.get())
                if minutes <= 0:
                    raise ValueError
            except ValueError:
                messagebox.showerror("Invalid amount", "Enter a positive number of minutes.", parent=dlg)
                return
            cost = int(round(minutes * rate))
            if cost > self._score_balance():
                messagebox.showerror(
                    "Not enough score",
                    f"That costs {cost} pts but your balance is only {self._score_balance()} pts.",
                    parent=dlg,
                )
                return
            self._score_add_ledger(-cost, "entertainment_purchase", detail=f"{minutes:g} min")
            if self.tracker:
                self.tracker.set_paid_until(datetime.now() + timedelta(minutes=minutes))
            self._refresh_score_sidebar()
            dlg.destroy()

        _dbtn = dict(bg=C["surface"], fg=C["text"], relief="flat",
                     activebackground=C["border"], activeforeground=C["text"])
        btn_row = tk.Frame(dlg, bg=C["bg"])
        btn_row.pack(pady=16)
        tk.Button(btn_row, text="Buy", command=_confirm, width=12, **_dbtn).pack(side="left", padx=6)
        tk.Button(btn_row, text="Cancel", command=dlg.destroy, width=10, **_dbtn).pack(side="left", padx=6)
        dlg.bind("<Return>", lambda e: _confirm())
        self._finalize_dialog(dlg)

