    def _tt_on_authorized(self):
        self._tt_mark_connected()

    def _tt_on_error(self, msg):
        if "redirect_uri" in msg.lower():
            self._show_redirect_uri_fix()
            self.tt_status_var.set(f"TickTick: error — {msg[:80]}")
            self.tt_connect_btn.config(state="normal")
            return
        # Any other failure (bad/rotated client_id or secret, expired code, etc.)
        # is most often fixed by re-entering credentials — but is_configured only
        # checks that *some* client_id/secret are saved, not that they still work,
        # so on_connect_ticktick() would otherwise keep silently retrying the same
        # stale pair with no way back into the setup dialog to overwrite them.
        messagebox.showerror("TickTick Error", msg, parent=self.root)
        if self._show_ticktick_setup():
            # Credentials were just saved — actually retry the connection instead
            # of leaving the dialog's "Save & Connect" label as an empty promise.
            self.on_connect_ticktick()
            return
        self.tt_status_var.set(f"TickTick: error — {msg[:80]}")
        self.tt_connect_btn.config(state="normal")

    # ── status bar ───────────────────────────────────────────────────────────

    def tick_status(self):
        total_today = 0
        done_today  = 0
        overdue_n   = 0

        for plan in self.plans:
            pid    = plan["id"]
            pday   = self._plan_day_for(plan)
            by_day = self._tasks_by_day_for(plan)
            t_today = by_day.get(pday, [])
            total_today += len(t_today)
            done_today  += sum(
                1 for t in t_today
                if self.completions.get((pid, pday, t.get("task", "")), False)
            )
            overdue_n += sum(
                1 for day in by_day if day < pday
                for t in by_day[day]
                if not self.completions.get((pid, day, t.get("task", "")), False)
            )

        self.date_var.set(self.today.strftime("%d.%m.%Y"))
        remaining = total_today - done_today

        if not self.plans:
            self.day_label_var.set("No plans active")
            self.status_var.set("Add a plan to begin")
            self._today_count_var.set("")
            self._overdue_count_var.set("")
        else:
            plan_count = len(self.plans)
            self.day_label_var.set(f"{plan_count} active plan{'s' if plan_count > 1 else ''}")
            self.status_var.set(f"{done_today}/{total_today} done today")
            self._today_count_var.set(str(remaining) if remaining else "")
            self._overdue_count_var.set(str(overdue_n) if overdue_n else "")
        # (deliberately NOT resetting list_title_var here — this tick fires
        # every 60s and used to clobber the "Weekly Report" title mid-view)

        self._pb_canvas.update_idletasks()
        w = self._pb_canvas.winfo_width() or 1
        fill_w = int(w * done_today / total_today) if total_today else 0
        self._pb_canvas.coords(self._pb_fill, 0, 0, fill_w, 4)

        nxt = self._next_eod_time()
        delta = (nxt - datetime.now()).total_seconds()
        if delta > 0:
            h, m = int(delta // 3600), int((delta % 3600) // 60)
            self.eod_var.set(f"EOD summary in {h}h {m}m")
        else:
            self.eod_var.set("EOD summary due now")

        # "Automatic" theme: follow a live OS light/dark switch without a
        # restart — cheap registry read, only rebuilds when the answer changes.
        mode = self.config.get("appearance", {}).get("theme_mode", "light")
        if mode == "auto" and _resolve_theme(mode) != getattr(self, "_resolved_theme", None):
            self._apply_theme(mode)
            self.build_interface()

        # tick_status is re-entered by build_interface (theme rebuilds) as well
        # as by its own timer — cancel any still-pending tick first so rebuilds
        # can't stack parallel 60s loops.
        if getattr(self, "_tick_after_id", None) is not None:
            try:
                self.root.after_cancel(self._tick_after_id)
            except Exception:
                pass
        self._tick_after_id = self.root.after(60_000, self.tick_status)

    # ── Phase 4 — reports ────────────────────────────────────────────────────

    def _show_today_view(self, scroll_to_overdue=False):
        self._active_view = "overdue" if scroll_to_overdue else "today"
        self._set_active_nav()
        self.list_title_var.set("Today")
        self.render_tasks()
        first_ov = getattr(self, "_first_overdue_widget", None)
        if scroll_to_overdue and first_ov is not None and first_ov.winfo_exists():
            self.task_frame.update_idletasks()
            self.canvas.yview_moveto(
                first_ov.winfo_y() / max(1, self.task_frame.winfo_height()))
        else:
            self.canvas.yview_moveto(0)

    def _show_report_view(self):
        self._active_view = "report"
        self._set_active_nav()
        self.list_title_var.set("Weekly Report")
        for w in self.task_frame.winfo_children():
            w.destroy()
        self._render_report()
        self.canvas.yview_moveto(0)

    # ── data queries ─────────────────────────────────────────────────────────

    def _day_task_counts(self, d):
        """(tasks_total, tasks_done) across all plans for a given calendar date."""
        tasks_total = 0
        tasks_done  = 0
        cur = self.conn.cursor()
        for plan in self.plans:
            pid = plan["id"]
            try:
                start = datetime.strptime(plan["start_date"], "%Y-%m-%d").date()
                day_num = (d - start).days + 1
            except Exception:
                continue
            by_day = self._tasks_by_day_for(plan)
            tasks_total += len(by_day.get(day_num, []))
            cur.execute(
                "SELECT COUNT(*) FROM task_completions WHERE plan_id=? AND plan_day=? AND completed=1",
                (pid, day_num)
            )
            tasks_done += cur.fetchone()[0]
        return tasks_total, tasks_done

    def _day_diary_minutes(self, d):
        """(on_plan_minutes, off_plan_minutes) from time_diary for a given calendar date.
        Deliberately excludes the 'paid' category — time bought with score isn't
        counted toward the off-plan penalty."""
        cur = self.conn.cursor()
        cur.execute(
            "SELECT category, SUM(duration_min) FROM time_diary "
            "WHERE date=? GROUP BY category",
            (d.isoformat(),)
        )
        act = {r[0]: r[1] for r in cur.fetchall()}
        return act.get("on_plan", 0), act.get("off_plan", 0)

    def _day_score(self, tasks_done, tasks_total, on_min, off_min, streak=0):
        """Score formula, reading rates from config.json's 'scoring' block (falling
        back to the original hardcoded defaults if a key is missing). streak is the
        number of consecutive fully-completed prior days — only meaningful for
        today's score, callers pass 0 for past days."""
        sc = self.config.get("scoring", {})
        task_pt    = sc.get("task_completed", 10)
        overdue_pt = sc.get("task_overdue_penalty", -5)
        on_hr_pt   = sc.get("on_plan_hour", 3)
        off_hr_pt  = sc.get("off_plan_hour", -2)
        streak_pt  = sc.get("streak_bonus_per_day", 5)
        raw = (
            tasks_done * task_pt
            + max(0, tasks_total - tasks_done) * overdue_pt
            + int(on_min  / 60 * on_hr_pt)
            + int(off_min / 60 * off_hr_pt)
            + streak_pt * streak
        )
        return max(raw, DAILY_SCORE_FLOOR)

    def _current_streak(self):
        """Consecutive fully-completed days immediately before today, most recent
        first, capped at 7 (matches the week-stats window)."""
        streak = 0
        for i in range(1, 8):
            d = date.today() - timedelta(days=i)
            tasks_total, tasks_done = self._day_task_counts(d)
            if tasks_total > 0 and tasks_done == tasks_total:
                streak += 1
            else:
                break
        return streak

    def _week_stats(self):
        stats  = []
        streak = self._current_streak()
        today  = date.today()
        for i in range(6, -1, -1):
            d = today - timedelta(days=i)
            tasks_total, tasks_done = self._day_task_counts(d)
            on_min, off_min = self._day_diary_minutes(d)
            score = self._day_score(tasks_done, tasks_total, on_min, off_min,
                                     streak=streak if d == today else 0)
            stats.append(dict(date=d,
                              tasks_done=tasks_done, tasks_total=tasks_total,
                              on_min=on_min, off_min=off_min, score=score))
        return stats

    # ── score ledger (spendable balance) ────────────────────────────────────

    def _score_balance(self):
        cur = self.conn.cursor()
        cur.execute("SELECT COALESCE(SUM(delta), 0) FROM score_ledger")
        return cur.fetchone()[0]

    def _score_add_ledger(self, delta, reason, detail=None, for_date=None):
        now = datetime.now()
        self.conn.execute(
            "INSERT INTO score_ledger (ts, date, delta, reason, detail) VALUES (?, ?, ?, ?, ?)",
            (now.isoformat(sep=" ", timespec="seconds"),
             (for_date or now.date()).isoformat(),
             delta, reason, detail),
        )
        self.conn.commit()

    def _score_rates(self):
        s = self.config.get("score", {})
        return (
            s.get("points_per_minute", 1.0),
            s.get("points_per_currency_unit", 10.0),
            s.get("currency_symbol", "€"),
        )

    def _credit_day_score_if_missing(self, d):
        """Insert a 'daily_score' ledger row for date d if one doesn't already
        exist. Returns the credited amount, or None if already credited."""
        cur = self.conn.cursor()
        cur.execute(
            "SELECT 1 FROM score_ledger WHERE reason='daily_score' AND date=?",
            (d.isoformat(),),
        )
        if cur.fetchone():
            return None
        tasks_total, tasks_done = self._day_task_counts(d)
        on_min, off_min = self._day_diary_minutes(d)
        streak = self._current_streak() if d == date.today() else 0
        score = self._day_score(tasks_done, tasks_total, on_min, off_min, streak=streak)
        try:
            self._score_add_ledger(score, "daily_score", detail=f"day score {score}", for_date=d)
        except sqlite3.IntegrityError:
            return None   # another process credited this date between check and insert
        return score

    def _credit_overdue_accrual_if_missing(self, d):
        """Deduct points for every task still overdue as of date d — one ledger
        row per calendar date, so a task left undone keeps costing points every
        day it stays outstanding, on top of the one-time miss already folded
        into its original day's daily_score. Guarded like _credit_day_score_if_
        missing so it never double-charges the same date."""
        cur = self.conn.cursor()
        cur.execute(
            "SELECT 1 FROM score_ledger WHERE reason='overdue_accrual' AND date=?",
            (d.isoformat(),),
        )
        if cur.fetchone():
            return None
        overdue_pt = self.config.get("scoring", {}).get("task_overdue_penalty", -5)
        count = 0
        for plan in self.plans:
            pid = plan["id"]
            try:
                start = datetime.strptime(plan["start_date"], "%Y-%m-%d").date()
                day_num = (d - start).days + 1
            except Exception:
                continue
            by_day = self._tasks_by_day_for(plan)
            for day, tasks in by_day.items():
                if day >= day_num:
                    continue
                # v2 rule (matches WinUI ScoreService): a task only bleeds
                # points for its first OVERDUE_ACCRUAL_CAP_DAYS overdue days,
                # then it's stale — replanning is the way out, not a spiral.
                if day_num - day > OVERDUE_ACCRUAL_CAP_DAYS:
                    continue
                for t in tasks:
                    if not self.completions.get((pid, day, t.get("task", "")), False):
                        count += 1
        if count == 0:
            return 0
        delta = count * overdue_pt
        try:
            self._score_add_ledger(
                delta, "overdue_accrual",
                detail=f"{count} task(s) still overdue ({OVERDUE_ACCRUAL_CAP_DAYS}-day cap)",
                for_date=d,
            )
        except sqlite3.IntegrityError:
            return None   # another process credited this date between check and insert
        return delta

    def _ensure_score_caught_up(self):
        """Startup catch-up: credit any of the last 7 days (bounded — same window
        as _week_stats) that ended without the app running at EOD to record it.
        Never touches today (not over yet) or anything older than 7 days, so this
        can't retroactively credit the whole plan history."""
        today = date.today()
        for i in range(7, 0, -1):
            d = today - timedelta(days=i)
            self._credit_day_score_if_missing(d)
            self._credit_overdue_accrual_if_missing(d)

    def _waste_patterns(self, period="week"):
        _cutoffs = {
            "day":   (True,  None),
            "week":  (False, "-7 days"),
            "month": (False, "-30 days"),
            "year":  (False, "-365 days"),
        }
        exact, offset = _cutoffs.get(period, _cutoffs["week"])
        cur = self.conn.cursor()
        if exact:
            cur.execute(
                "SELECT window, SUM(duration_min) as mins FROM time_diary "
                "WHERE category='off_plan' AND date = date('now') GROUP BY window"
            )
        else:
            cur.execute(
                "SELECT window, SUM(duration_min) as mins FROM time_diary "
                "WHERE category='off_plan' AND date >= date('now', ?) GROUP BY window",
                (offset,),
            )
        aggregated: dict = {}
        for window, mins in cur.fetchall():
            app = self._extract_app_name(window)
            aggregated[app] = aggregated.get(app, 0) + mins
        return sorted(aggregated.items(), key=lambda x: x[1], reverse=True)[:8]

    def _app_time_breakdown(self, period="week"):
        """Return hierarchical app usage for the chosen period.
        Structure: [(app_name, {total, on_plan, off_plan, neutral,
                                 subs: {sub_name: {total, on_plan, off_plan, neutral}}})]
        """
        _cutoffs = {
            "day":   (True,  None),
            "week":  (False, "-7 days"),
            "month": (False, "-30 days"),
            "year":  (False, "-365 days"),
        }
        exact, offset = _cutoffs.get(period, _cutoffs["week"])
        cur = self.conn.cursor()
        if exact:
            cur.execute(
                "SELECT window, category, SUM(duration_min) as mins FROM time_diary "
                "WHERE date = date('now') GROUP BY window, category"
            )
        else:
            cur.execute(
                "SELECT window, category, SUM(duration_min) as mins FROM time_diary "
                "WHERE date >= date('now', ?) GROUP BY window, category",
                (offset,),
            )
        groups: dict = {}
        for window, cls, mins in cur.fetchall():
            grp = self._get_app_group(window)
            sub = self._get_app_sub(window)
            if grp not in groups:
                groups[grp] = {"total": 0, "on_plan": 0, "off_plan": 0,
                                "neutral": 0, "subs": {}}
            groups[grp]["total"] += mins
            groups[grp][cls] = groups[grp].get(cls, 0) + mins
            if sub:
                if sub not in groups[grp]["subs"]:
                    groups[grp]["subs"][sub] = {"total": 0, "on_plan": 0,
                                                "off_plan": 0, "neutral": 0}
                groups[grp]["subs"][sub]["total"] += mins
                groups[grp]["subs"][sub][cls] = \
                    groups[grp]["subs"][sub].get(cls, 0) + mins
        return sorted(groups.items(), key=lambda x: x[1]["total"], reverse=True)[:12]

    def _suggestions(self, stats, patterns):
        hints = []

        total_off = sum(s["off_min"] for s in stats)
        total_on  = sum(s["on_min"]  for s in stats)
        if total_off > 120:
            hints.append(
                f"You spent {total_off // 60}h {total_off % 60}m off-plan this week. "
                "Try blocking distracting apps during working hours."
            )

        low_days = [s for s in stats if s["tasks_total"] > 0
                    and s["tasks_done"] / s["tasks_total"] < 0.5]
        if len(low_days) >= 3:
            hints.append(
                f"Task completion was below 50% on {len(low_days)} days this week. "
                "Consider reducing the daily task count or starting earlier."
            )

        if total_on > 0 and total_off / max(total_on, 1) > 0.4:
            hints.append(
                "Off-plan time is over 40% of your productive time. "
                "Your goal needs tighter focus blocks."
            )

        if patterns:
            top_app = patterns[0][0].split(" - ")[-1][:40]
            top_min = patterns[0][1]
            hints.append(
                f"'{top_app}' is your biggest distraction — "
                f"{top_min} min off-plan this week."
            )

        if not hints:
            hints.append("Great week — no major distraction patterns detected. Keep going!")

        return hints

    # ── report rendering ─────────────────────────────────────────────────────

    def _report_section(self, title):
        f = tk.Frame(self.task_frame, bg=C["bg"])
        f.pack(fill="x", padx=24, pady=(20, 6))
        tk.Label(f, text=title, font=("Segoe UI", 11, "bold"),
                 fg=C["text_dim"], bg=C["bg"]).pack(anchor="w")
        tk.Frame(self.task_frame, bg=C["separator"], height=1).pack(fill="x", padx=24)

    _PERIOD_OPTS = [("Day", "day"), ("Week", "week"), ("Month", "month"), ("Year", "year")]
    _PERIOD_NAME = {"day": "TODAY", "week": "THIS WEEK",
                    "month": "THIS MONTH", "year": "THIS YEAR"}

    def _set_report_period(self, period):
        self._report_period = period
        for w in self.task_frame.winfo_children():
            w.destroy()
        self._render_report()

    @staticmethod
    def _fmt_mins(mins):
        h, m = divmod(int(mins), 60)
        return f"{h}h {m}m" if h else f"{m}m"

    def _period_table_rows(self):
        """Summary table rows adapted to self._report_period."""
        p = self._report_period
        if p in ("day", "week"):
            rows = self._week_stats()
            return rows if p == "week" else [r for r in rows if r["date"] == date.today()]

        cur = self.conn.cursor()

        if p == "month":
            today  = date.today()
            start  = today - timedelta(days=29)
            # Build ordered week-bucket dict keyed by Monday of each week
            weeks  = {}
            d = start
            while d <= today:
                ws  = d - timedelta(days=d.weekday())
                key = ws.isoformat()
                if key not in weeks:
                    weeks[key] = {"week_start": ws, "on_min": 0, "off_min": 0}
                d += timedelta(days=1)
            cur.execute(
                "SELECT date, category, SUM(duration_min) FROM time_diary "
                "WHERE date >= ? GROUP BY date, category",
                (start.isoformat(),)
            )
            for ds, cat, mins in cur.fetchall():
                d2  = date.fromisoformat(ds)
                ws  = d2 - timedelta(days=d2.weekday())
                key = ws.isoformat()
                if key in weeks and cat in ("on_plan", "off_plan"):
                    weeks[key]["on_min" if cat == "on_plan" else "off_min"] += mins
            rows = []
            for key in sorted(weeks.keys()):
                w  = weeks[key]
                ws = w["week_start"]
                we = ws + timedelta(days=6)
                rows.append({"label": f"{ws.strftime('%d %b')} – {we.strftime('%d %b')}",
                             "on_min": w["on_min"], "off_min": w["off_min"]})
            return rows

        # year — group by calendar month
        start = date.today() - timedelta(days=364)
        cur.execute(
            "SELECT strftime('%Y-%m', date) as mo, category, SUM(duration_min) "
            "FROM time_diary WHERE date >= ? GROUP BY mo, category ORDER BY mo",
            (start.isoformat(),)
        )
        months: dict = {}
        for mo, cat, mins in cur.fetchall():
            if mo not in months:
                months[mo] = {"on_min": 0, "off_min": 0}
            if cat in ("on_plan", "off_plan"):
                months[mo]["on_min" if cat == "on_plan" else "off_min"] += mins
        rows = []
        for mo in sorted(months.keys()):
            try:
                label = datetime.strptime(mo, "%Y-%m").strftime("%B %Y")
            except Exception:
                label = mo
            rows.append({"label": label, **months[mo]})
        return rows

    def _render_report(self):
        p        = self._report_period
        pname    = self._PERIOD_NAME[p]
        stats    = self._week_stats()          # always week for score card + insights
        today_s  = stats[-1]
        patterns = self._waste_patterns(p)
        hints    = self._suggestions(stats, patterns)

        # ── Period selector (top of page) ─────────────────────────────────────
        sel_row = tk.Frame(self.task_frame, bg=C["bg"])
        sel_row.pack(fill="x", padx=24, pady=(16, 8))
        for lbl, key in self._PERIOD_OPTS:
            active = (p == key)
            tk.Button(
                sel_row, text=lbl,
                font=("Segoe UI", 10, "bold" if active else "normal"),
                fg="white" if active else C["text_dim"],
                bg=C["accent_blue"] if active else C["surface"],
                activebackground=C["accent_blue"], activeforeground="white",
                relief="flat", padx=14, pady=5, cursor="hand2",
                command=lambda k=key: self._set_report_period(k),
            ).pack(side="left", padx=(0, 6))

        # ── Score card (always today) ─────────────────────────────────────────
        score     = today_s["score"]
        score_col = (C["accent_green"] if score >= 20
                     else C["accent_red"] if score < 0 else C["accent_amber"])
        card  = tk.Frame(self.task_frame, bg=C["surface"])
        card.pack(fill="x", padx=24, pady=(0, 0))
        inner = tk.Frame(card, bg=C["surface"], padx=24, pady=16)
        inner.pack(fill="x")
        tk.Label(inner, text="Today's Score", font=("Segoe UI", 10),
                 fg=C["text_dim"], bg=C["surface"]).pack(anchor="w")
        tk.Label(inner, text=str(score), font=("Segoe UI", 40, "bold"),
                 fg=score_col, bg=C["surface"]).pack(anchor="w")
        detail = (f"{today_s['tasks_done']}/{today_s['tasks_total']} tasks  ·  "
                  f"{today_s['on_min']}m on-plan  ·  {today_s['off_min']}m off-plan")
        tk.Label(inner, text=detail, font=("Segoe UI", 9),
                 fg=C["text_dim"], bg=C["surface"]).pack(anchor="w", pady=(4, 0))

        # ── Stats table ───────────────────────────────────────────────────────
        self._report_section(pname)
        table_rows = self._period_table_rows()
        tbl = tk.Frame(self.task_frame, bg=C["bg"])
        tbl.pack(fill="x", padx=24, pady=4)

        if p in ("day", "week"):
            for ci, hdr in enumerate(["Day", "Tasks", "On-plan", "Off-plan", "Score"]):
                tk.Label(tbl, text=hdr, font=("Segoe UI", 8, "bold"),
                         fg=C["text_muted"], bg=C["bg"], width=10, anchor="w").grid(
                             row=0, column=ci, padx=(0, 8), pady=(4, 2))
            for ri, s in enumerate(table_rows, start=1):
                is_today = s["date"] == date.today()
                fg = C["text"] if is_today else C["text_dim"]
                fw = "bold" if is_today else "normal"
                vals = [s["date"].strftime("%a %d.%m"),
                        f"{s['tasks_done']}/{s['tasks_total']}",
                        self._fmt_mins(s["on_min"]),
                        self._fmt_mins(s["off_min"]),
                        str(s["score"])]
                for ci, val in enumerate(vals):
                    sfg = fg
                    if ci == 4:
                        v = s["score"]
                        sfg = (C["accent_green"] if v >= 20
                               else C["accent_red"] if v < 0 else C["accent_amber"])
                    tk.Label(tbl, text=val, font=("Segoe UI", 10, fw),
                             fg=sfg, bg=C["bg"], width=10, anchor="w").grid(
                                 row=ri, column=ci, padx=(0, 8), pady=2)
        else:
            for ci, hdr in enumerate(["Period", "On-plan", "Off-plan", "Total"]):
                w = 16 if ci == 0 else 10
                tk.Label(tbl, text=hdr, font=("Segoe UI", 8, "bold"),
                         fg=C["text_muted"], bg=C["bg"], width=w, anchor="w").grid(
                             row=0, column=ci, padx=(0, 8), pady=(4, 2))
            for ri, s in enumerate(table_rows, start=1):
                total = s["on_min"] + s["off_min"]
                vals  = [s["label"],
                         self._fmt_mins(s["on_min"]),
                         self._fmt_mins(s["off_min"]),
                         self._fmt_mins(total)]
                widths = [16, 10, 10, 10]
                for ci, val in enumerate(vals):
                    tk.Label(tbl, text=val, font=("Segoe UI", 10),
                             fg=C["text_dim"], bg=C["bg"], width=widths[ci], anchor="w").grid(
                                 row=ri, column=ci, padx=(0, 8), pady=2)

        # ── Top distractions ─────────────────────────────────────────────────
        self._report_section(f"TOP DISTRACTIONS — {pname}")
        if not patterns:
            tk.Label(self.task_frame, text="No off-plan activity logged.",
                     font=("Segoe UI", 10), fg=C["text_muted"], bg=C["bg"],
                     padx=24, pady=4).pack(anchor="w")
        else:
            max_mins = patterns[0][1]
            for app, mins in patterns:
                row_f = tk.Frame(self.task_frame, bg=C["bg"])
                row_f.pack(fill="x", padx=24, pady=3)
                tk.Label(row_f, text=app[:50], font=("Segoe UI", 10),
                         fg=C["text"], bg=C["bg"], width=32, anchor="w").pack(side="left")
                bar_bg = tk.Frame(row_f, bg=C["surface"], height=6, width=140)
                bar_bg.pack(side="left", padx=(8, 4))
                bar_bg.pack_propagate(False)
                fill_w = max(4, int(140 * mins / max(max_mins, 1)))
                tk.Frame(bar_bg, bg=C["accent_red"], width=fill_w, height=6).place(x=0, y=0)
                tk.Label(row_f, text=self._fmt_mins(mins), font=("Segoe UI", 8),
                         fg=C["text_muted"], bg=C["bg"]).pack(side="left")

        # ── Time by app ───────────────────────────────────────────────────────
        self._report_section(f"TIME BY APP — {pname}")
        breakdown = self._app_time_breakdown(p)
        if not breakdown:
            tk.Label(self.task_frame, text="No activity logged yet.",
                     font=("Segoe UI", 10), fg=C["text_muted"], bg=C["bg"],
                     padx=24, pady=4).pack(anchor="w")
        else:
            max_total = breakdown[0][1]["total"]

            def _make_bar(parent, data, width=140):
                bg_f = tk.Frame(parent, bg=C["surface"], height=6, width=width)
                bg_f.pack(side="left", padx=(4, 6))
                bg_f.pack_propagate(False)
                x = 0
                for cat, col in [("on_plan",  C["accent_green"]),
                                  ("off_plan", C["accent_red"]),
                                  ("neutral",  C["accent_blue"])]:
                    w = int(width * data.get(cat, 0) / max(max_total, 1))
                    if w > 0:
                        tk.Frame(bg_f, bg=col, width=w, height=6).place(x=x, y=0)
                        x += w

            for app_name, app_data in breakdown:
                group_f   = tk.Frame(self.task_frame, bg=C["bg"])
                group_f.pack(fill="x")
                subs      = sorted(app_data["subs"].items(),
                                   key=lambda kv: kv[1]["total"], reverse=True)
                sub_frame = tk.Frame(group_f, bg=C["bg"])
